Code:
public int[] zeroMax(int[] nums) {
    int n = nums.length;
    int maxOdd = Integer.MIN_VALUE;
    for (int i = n - 1; i >= 0; i--) {
        if (nums[i] % 2 != 0) {
            maxOdd = Math.max(maxOdd, nums[i]);
            nums[i] = -1;
        }
    }
    for (int i = 0; i < n; i++) {
        if (nums[i] == 0 && maxOdd != Integer.MIN_VALUE) {
            nums[i] = maxOdd;
            maxOdd = Integer.MIN_VALUE;
        }
    }
    return nums;
}

public int[] shiftLeft(int[] nums) {
    int N = nums.length;
    if (N == 0 || N == 1) return nums;
    int temp = nums[0];
    for (int i = 0; i < N - 1; i++) {
        nums[i] = nums[i + 1];
    }
    nums[N - 1] = temp;
    return nums;
}

