public int[] fix45(int[] nums) {
    int n = nums.length;
    int i = 0, j = 0;

    while (j < n) {
        if (nums[j] == 5) {
            while (i < j && nums[i] != 4) {
                i++;
            }
            if (i < j) {
                int temp = nums[i+1];
                nums[i+1] = nums[j];
                nums[j] = temp;
            }
        }
        j++;
    }
    return nums;
}

